CREATE TABLE DISTRITO (
    ID_DISTRITO NUMBER NOT NULL,
    NOMBRE VARCHAR2(5) NOT NULL,
    PRIMARY KEY (ID_DISTRITO)
);

-- MODIFICAR EL TAMANIO DEL CAMPO NOMBRE DE LA TABLA DISTRITO DE TAL MANERA QUE SU TAMANIO SEA 20
ALTER TABLE DISTRITO MODIFY NOMBRE VARCHAR2(20);

-- AGREGAR LA COLUMNA SUELDO DE TIPO NUMBER A LA TABLA PERSONA CON UN VALOR POR DEFECTO DE 1000
ALTER TABLE PERSONA ADD SUELDO NUMBER DEFAULT 1000;

-- AGREGAR EN LA TABLA PERSONA EL CAMPO ID_DISTRITO DE TIPO NUMBER
ALTER TABLE PERSONA ADD ID_DISTRITO NUMBER;

-- AGREGAR EN LA TABLA PERSONA EL CAMPO FECHA_NACIMIENTO DEL TIPO DATE
ALTER TABLE PERSONA ADD FECHA_NACIMIENTO DATE;

-- HACER QUE EL CAMPO ID_DISTRITO RECIEN ANIADIDO A LA TABLA PERSONA SEA UNA CLAVE FORANEA QUE HAGA REFERENCIA A LA TABLA DISTIRTO
ALTER TABLE PERSONA ADD FOREIGN KEY (ID_DISTRITO) REFERENCES DISTRITO (ID_DISTRITO);

-- INSERTAR ALGUNOS DATOS EN LA TABLA DISTRITO

-- MOSTRAR EL CONTENIDO DE LA TABLA DISTRITO
SELECT * FROM DISTRITO;

-- COPIAR EL CONTENIDO DEL ARCHIVO INF246_2020-1_LAB2_DIRIGIDA_inserts.sql EN LA HOJA DE TRABAJO Y EJECUTAR EL SCRIPT

-- MOSTRAR EL CONTENIDO DE LA TABLA PERSONA
SELECT * FROM PERSONA;

-- MOSTRAR LOS APELLIDOS Y NOMBRE DE LAS PERSONAS, ORDENADAS POR APELLIDO PATERNO
SELECT APE_PATERNO, APE_MATERNO, NOMBRE
FROM PERSONA
ORDER BY APE_PATERNO;

-- MOSTRAR APELLIDOS, NOMBRES Y SUELDO DE TODAS LAS PERSONAS DE SEXO FEMENINO, ORDENADAS POR EL SUELDO DE FORMA DESCENDIENTE. SI HAY SUELDOS IGUALES, ORDENAR POR APELLIDO PATERNO DE FORMA ASCENDENTE
SELECT APE_PATERNO, APE_MATERNO, NOMBRE, SUELDO
FROM PERSONA
WHERE SEXO = 'F'
ORDER BY SUELDO DESC, APE_PATERNO ASC;

-- MOSTRAR LOS APELLIDOS Y NOMBRES CONCATENADOS CON ESPACIOS Y COMAS, Y EL SUELDO DE TODAS LAS PERSONAS DE SEXO MASCULINO
SELECT APE_PATERNO || ' ' || APE_MATERNO || ', ' || NOMBRE AS NOMBRE_COMPLETO, SUELDO
FROM PERSONA
WHERE SEXO = 'M';

-- MOSTRAR LOS APELLIDOS, NOMBRE, SEXO, FECHA DE NACIMIENTO, ORDENADOS ASCENDENTEMENTE POR FECHA DE NACIMIENTO
SELECT APE_PATERNO, APE_MATERNO, NOMBRE, SEXO, TO_CHAR(FECHA_NACIMIENTO, 'DD/MM/YYYY') AS FECHANACIMIENTO
FROM PERSONA
ORDER BY FECHA_NACIMIENTO ASC;

-- MOSTRAR LOS APELLIDOS, NOMBRE, SEXO, FECHA DE NACIMIENTO (DD/MM) DE LAS PERSONAS QUE NACIERON EN EL ANIO 2000, ORDENADOS ALFABETICAMENTE POR EL APELLIDO PATERNO
SELECT APE_PATERNO, APE_MATERNO, NOMBRE, SEXO, TO_CHAR(FECHA_NACIMIENTO, 'DD/MM') AS DIA_MES
FROM PERSONA
WHERE FECHA_NACIMIENTO BETWEEN TO_DATE('01/01/2000', 'DD/MM/YYYY') AND TO_DATE('31/12/2000', 'DD/MM/YY')
ORDER BY APE_PATERNO ASC;

-- MOSTRAR LOS APELLIDOS, NOMBRE Y SEXO DE LAS PERSONAS, Y LOS DISTRITOS DONDE VIVEN ORDENADOS ALFABETICAMENTE POR EL NOMBRE DEL DISTRITO
SELECT APE_PATERNO, APE_MATERNO, P.NOMBRE, SEXO, D.NOMBRE
FROM PERSONA P, DISTRITO D
WHERE P.ID_DISTRITO = D.ID_DISTRITO
ORDER BY D.NOMBRE ASC;

-- MOSTRAR LOS APELLIDOS Y NOMBRES DE LAS MUJERES QUE VIVEN EN SURCO
SELECT P.APE_PATERNO, P.APE_MATERNO, P.NOMBRE
FROM PERSONA P, DISTRITO D
WHERE P.SEXO = 'F' AND P.ID_DISTRITO = D.ID_DISTRITO AND D.NOMBRE = 'Surco';

-- MOSTRAR EL NOMBRE COMPLETO DE LAS PERSONAS QUE NACIERON EN EL ANIO 2000 Y QUE VIVEN EN SURCO
SELECT P.APE_PATERNO || ' ' || P.APE_MATERNO || ', ' || P.NOMBRE AS NOMBRE_COMPLETO
FROM PERSONA P, DISTRITO D
WHERE P.ID_DISTRITO = D.ID_DISTRITO AND D.NOMBRE = 'Surco' AND FECHA_NACIMIENTO BETWEEN TO_DATE('01/01/2000', 'DD/MM/YYYY') AND TO_DATE('31/12/2000', 'DD/MM/YY');

-- MOSTRAR EL NOMBRE COMPLETO DE LAS PERSONAS CUYO APELLIDO PATERNO EMPIEZA CON LA LETRA B, Y SU SUELDO EN SOLES. CONSIDERAR UNA TASA DE CAMBIO DE 3.40 SOLES POR CADA DOLAR
SELECT P.APE_PATERNO || ' ' || P.APE_MATERNO || ', ' || P.NOMBRE AS NOMBRE_COMPLETO, P.SUELDO * 3.4 AS SUELDO_SOLES
FROM PERSONA P
WHERE P.APE_PATERNO LIKE 'B%';

-- INCREMENTAR EN 100 DOLARES EL SUELDO DE LAS PERSONAS QUE GANAN ENTRE 1000 Y 2000 DOLARES
UPDATE PERSONA
SET SUELDO = SUELDO + 100
WHERE SUELDO BETWEEN 1000 AND 2000;

-- ACTUALIZAR EL SUELDO DE LAS PERSONAS QUE GANAN MAS DE 4800 DOLARES, DESCONTANDOLES EL 5% DEL SUELDO
UPDATE PERSONA
SET SUELDO = 95 * SUELDO / 100
WHERE SUELDO > 4800;

-- MOSTRAR LA SUMA DE SUELDOS, PROMEDIO DE SUELDOS, SUELDO MAXIMO Y SUELDO MINIMO DE TODAS LAS PERSONAS
SELECT SUM(SUELDO), AVG(SUELDO), MAX(SUELDO), MIN(SUELDO)
FROM PERSONA;

-- MOSTRAR LA CANTIDAD DE VARONES QUE GANAN MAS DE 3000 DOLARES
SELECT COUNT(*)
FROM PERSONA
WHERE SEXO = 'M' AND SUELDO > 3000;

-- ELIMINAR LOS DATOS DE LAS PERSONAS QUE GANAN MAS DE 4500 DOLARES
DELETE FROM PERSONA
WHERE SUELDO > 4500;

-- ELIMINAR LOS DATOS DE LAS PERSONAS QUE NACIERON EN EL ANIO 1996
DELETE FROM PERSONA
WHERE FECHA_NACIMIENTO BETWEEN TO_DATE('01/01/1996', 'DD/MM/YYYY') AND TO_DATE('31/12/1996', 'DD/MM/YYYY');